"""Example figure generated by the paper-figures system.

Demonstrates the §0b quality bar on a single hero figure:
  - depth      : the fitted response + its 95% CI band are drawn, and the
                 fitted optimum (with uncertainty) is annotated (not just points)
  - elegance   : one panel, one claim
  - unimpeachable: 95% CI band, N annotated, units on both axes, reproducible
  - visible gap: paper_style() typography + palette + editable vector output

Pure numpy + matplotlib (no scipy/sklearn), so `git clone && python examples/gallery.py`
just works. Output is written next to this script as example_hero.{png,pdf,svg}.
"""
import sys
from pathlib import Path

sys.path.insert(0, str(Path(__file__).resolve().parent.parent / "scripts"))
from _style import paper_style, save

import numpy as np
import matplotlib.pyplot as plt

PALETTE, MARKERS, LS = paper_style(font="sans")
rng = np.random.default_rng(7)

# --- synthetic measurement: a response with a genuine optimum (e.g. yield vs
#     a process condition), so a quadratic is the correct model ---
N = 120
x = np.sort(rng.uniform(0, 24, N))                   # condition (e.g. temperature, a.u.)
x_star, peak = 15.0, 1.02
true = peak - 0.0055 * (x - x_star) ** 2             # concave response with a real optimum
y = true + rng.normal(0, 0.05, N)                    # observations

# --- 2nd-order polynomial fit with a 95% confidence band from the fit covariance ---
deg = 2
coef, cov = np.polyfit(x, y, deg, cov=True)
xs = np.linspace(x.min(), x.max(), 200)
V = np.vander(xs, deg + 1)                            # design matrix at xs
yhat = V @ coef
se = np.sqrt(np.einsum("ij,jk,ik->i", V, cov, V))    # std error of the fit
lo, hi = yhat - 1.96 * se, yhat + 1.96 * se

# fitted optimum x* = -b/2a, with a 1st-order (delta-method) uncertainty
a, b = coef[0], coef[1]
xopt = -b / (2 * a)
g = np.array([b / (2 * a ** 2), -1 / (2 * a), 0.0])  # d(xopt)/d(coef)
xopt_se = float(np.sqrt(g @ cov @ g))

# --- plot ---
fig, ax = plt.subplots(figsize=(6.2, 3.6))
ax.scatter(x, y, s=14, color=PALETTE[0], alpha=0.45,
           edgecolor="white", linewidth=0.3, label="Observations", zorder=2)
ax.fill_between(xs, lo, hi, color=PALETTE[1], alpha=0.18,
                label="95% CI", zorder=1)
ax.plot(xs, yhat, color=PALETTE[1], lw=2, label="Fit", zorder=3)

# annotation as narrative: the fitted optimum (the figure's headline) + its CI
ax.axvline(xopt, color="#3a3a3a", lw=0.8, ls="--", zorder=1)
ax.annotate(f"optimum\n$x^* = {xopt:.1f} \\pm {1.96*xopt_se:.1f}$",
            xy=(xopt, yhat.max()), xytext=(xopt + 2.2, 0.45),
            fontsize=8, ha="left",
            arrowprops=dict(arrowstyle="->", lw=0.8, color="#3a3a3a"))

ax.set_xlabel("Process condition $x$ (a.u.)")
ax.set_ylabel("Yield $y$ (a.u.)")
ax.text(0.03, 0.06, f"$N={N}$", transform=ax.transAxes, ha="left", fontsize=8,
        color="#3a3a3a")
ax.legend(loc="lower right")
ax.set_ylim(-0.05, 1.18)

save(fig, "example_hero", outdir=str(Path(__file__).resolve().parent))
plt.close(fig)
print("[example] wrote examples/example_hero.{pdf,png,svg}")
